class JSZip {
  constructor() {
    this.files = [];
  }

  file(name, data) {
    this.files.push({ name, data });
    return this;
  }

  async generateAsync(options = {}, onUpdate) {
    const encoder = new TextEncoder();
    const zipParts = [];
    const centralParts = [];
    const files = this.files;
    const totalBytes = files.reduce((sum, file) => sum + (file.data && typeof file.data.size === "number" ? file.data.size : 0), 0);
    let loadedBytes = 0;
    let offset = 0;

    const notify = (percent, currentFile) => {
      if (typeof onUpdate === "function") {
        onUpdate({
          percent: Math.max(0, Math.min(100, percent)),
          currentFile,
          loaded: loadedBytes,
          total: totalBytes
        });
      }
    };

    notify(0, files[0] ? files[0].name : undefined);

    for (let index = 0; index < files.length; index += 1) {
      const file = files[index];
      const data = new Uint8Array(await toArrayBuffer(file.data));
      const name = encoder.encode(file.name);
      const basePercent = files.length ? (index / files.length) * 100 : 100;
      const nextPercent = files.length ? ((index + 1) / files.length) * 100 : 100;
      const crc = await crcAsync(data, (loadedInFile) => {
        loadedBytes = files.slice(0, index).reduce((sum, item) => sum + (item.data && typeof item.data.size === "number" ? item.data.size : 0), 0) + loadedInFile;
        const fileRatio = data.length ? loadedInFile / data.length : 1;
        notify(basePercent + (nextPercent - basePercent) * fileRatio * 0.8, file.name);
      });
      loadedBytes = files.slice(0, index + 1).reduce((sum, item) => sum + (item.data && typeof item.data.size === "number" ? item.data.size : 0), 0);

      const localHeader = [];
      put(localHeader, 4, 0x04034b50);
      put(localHeader, 2, 20);
      put(localHeader, 2, 0);
      put(localHeader, 2, 0);
      put(localHeader, 2, 0);
      put(localHeader, 2, 0);
      put(localHeader, 4, crc);
      put(localHeader, 4, data.length);
      put(localHeader, 4, data.length);
      put(localHeader, 2, name.length);
      put(localHeader, 2, 0);
      zipParts.push(new Uint8Array(localHeader), name, data);

      const centralHeader = [];
      put(centralHeader, 4, 0x02014b50);
      put(centralHeader, 2, 20);
      put(centralHeader, 2, 20);
      put(centralHeader, 2, 0);
      put(centralHeader, 2, 0);
      put(centralHeader, 2, 0);
      put(centralHeader, 2, 0);
      put(centralHeader, 4, crc);
      put(centralHeader, 4, data.length);
      put(centralHeader, 4, data.length);
      put(centralHeader, 2, name.length);
      put(centralHeader, 2, 0);
      put(centralHeader, 2, 0);
      put(centralHeader, 2, 0);
      put(centralHeader, 2, 0);
      put(centralHeader, 4, 0);
      put(centralHeader, 4, offset);
      centralParts.push(new Uint8Array(centralHeader), name);

      offset += localHeader.length + name.length + data.length;
      notify(nextPercent, file.name);
      await yieldToBrowser();
    }

    const centralDirectorySize = centralParts.reduce((sum, part) => sum + part.length, 0);
    const centralDirectoryStart = offset;
    zipParts.push(...centralParts);

    const end = [];
    put(end, 4, 0x06054b50);
    put(end, 2, 0);
    put(end, 2, 0);
    put(end, 2, files.length);
    put(end, 2, files.length);
    put(end, 4, centralDirectorySize);
    put(end, 4, centralDirectoryStart);
    put(end, 2, 0);
    zipParts.push(new Uint8Array(end));

    await yieldToBrowser();
    notify(100, files[files.length - 1] ? files[files.length - 1].name : undefined);

    if (options.type && options.type !== "blob") {
      throw new Error("This lightweight JSZip implementation only supports type: 'blob'.");
    }
    return new Blob(zipParts, { type: "application/zip" });
  }
}

const CRC_TABLE = (() => {
  const table = new Uint32Array(256);
  for (let n = 0; n < 256; n += 1) {
    let c = n;
    for (let k = 0; k < 8; k += 1) c = (c & 1) ? (0xedb88320 ^ (c >>> 1)) : (c >>> 1);
    table[n] = c >>> 0;
  }
  return table;
})();

function put(array, bytes, value) {
  for (let i = 0; i < bytes; i += 1) array.push((value >>> (i * 8)) & 255);
}

async function crcAsync(data, onProgress) {
  let crc = -1;
  const chunkSize = 256 * 1024;
  for (let offset = 0; offset < data.length; offset += chunkSize) {
    const end = Math.min(offset + chunkSize, data.length);
    for (let i = offset; i < end; i += 1) crc = CRC_TABLE[(crc ^ data[i]) & 255] ^ (crc >>> 8);
    if (typeof onProgress === "function") onProgress(end);
    await yieldToBrowser();
  }
  if (data.length === 0 && typeof onProgress === "function") onProgress(0);
  return (crc ^ -1) >>> 0;
}

function toArrayBuffer(data) {
  if (data && typeof data.arrayBuffer === "function") return data.arrayBuffer();
  if (data instanceof ArrayBuffer) return Promise.resolve(data);
  if (ArrayBuffer.isView(data)) return Promise.resolve(data.buffer.slice(data.byteOffset, data.byteOffset + data.byteLength));
  return new Blob([data]).arrayBuffer();
}

function yieldToBrowser() {
  return new Promise((resolve) => {
    if (typeof requestAnimationFrame === "function") requestAnimationFrame(() => resolve());
    else setTimeout(resolve, 0);
  });
}

if (typeof window !== "undefined") window.JSZip = JSZip;
